#!/usr/bin/env python3 """生成示例 Octomap 数据用于测试和演示。 用法： python tools/generate_sample_map.py --out data/sample_map.npz """ import argparse import numpy as np from pathlib import Path def generate_sample_map( grid_w: int = 64, grid_h: int = 64, grid_scale: float = 1.0, seed: int = 42, ) -> tuple[np.ndarray, np.ndarray]: """生成示例 2D 占据栅格和 Z 波段数据。 Args: grid_w: 网格宽度 grid_h: 网格高度 grid_scale: 网格比例 seed: 随机种子 Returns: occ2d: uint8[H,W] 占据栅格 z_band2d: float32[H,W,2] Z 波段数据 """ np.random.seed(seed) # 生成基础占据栅格（随机障碍物） occ2d = np.zeros((grid_h, grid_w), dtype=np.uint8) # 生成一些障碍物区域 for _ in range(15): cx = np.random.randint(0, grid_w) cy = np.random.randint(0, grid_h) size = np.random.randint(3, 10) x0 = max(0, cx - size // 2) x1 = min(grid_w, cx + size // 2) y0 = max(0, cy - size // 2) y1 = min(grid_h, cy + size // 2) occ2d[y0:y1, x0:x1] = 255 # 生成 Z 波段数据 z_band2d = np.zeros((grid_h, grid_w, 2), dtype=np.float32) # 为占据的格子生成高度信息 for y in range(grid_h): for x in range(grid_w): if occ2d[y, x] > 0: # 随机生成建筑物或树木高度 if np.random.random() < 0.3: # 树木（canopy 模式） height = np.random.uniform(2.0, 5.0) z_lo = max(0, height - 1.0) # 树冠向下膨胀 1m else: # 建筑物/地面障碍（grounded 模式） height = np.random.uniform(0.5, 3.0) z_lo = 0.0 z_band2d[y, x, 0] = z_lo z_band2d[y, x, 1] = height return occ2d, z_band2d def main(): parser = argparse.ArgumentParser(description="生成示例 Octomap 数据") parser.add_argument("--grid-w", type=int, default=64, help="网格宽度") parser.add_argument("--grid-h", type=int, default=64, help="网格高度") parser.add_argument("--grid-scale", type=float, default=1.0, help="网格比例") parser.add_argument("--seed", type=int, default=42, help="随机种子") parser.add_argument("--out", type=str, default="data/sample_map.npz", help="输出 NPZ 文件路径") args = parser.parse_args() print(f"生成示例地图数据...") print(f"  网格大小：{args.grid_w}x{args.grid_h}") print(f"  网格比例：{args.grid_scale}") print(f"  随机种子：{args.seed}") occ2d, z_band2d = generate_sample_map( grid_w=args.grid_w, grid_h=args.grid_h, grid_scale=args.grid_scale, seed=args.seed, ) # 保存到 NPZ out_path = Path(args.out) out_path.parent.mkdir(parents=True, exist_ok=True) np.savez_compressed( out_path, occ2d=occ2d, z_band2d=z_band2d, grid_w=np.int32(args.grid_w), grid_h=np.int32(args.grid_h), grid_scale=np.float32(args.grid_scale), revision=np.int32(1), ) print(f"已保存：{out_path}") print(f"  occ2d: shape={occ2d.shape}, dtype={occ2d.dtype}, occupied={np.sum(occ2d > 0)}") print(f"  z_band2d: shape={z_band2d.shape}, dtype={z_band2d.dtype}") # 显示统计信息 z_lo = z_band2d[..., 0] z_hi = z_band2d[..., 1] occupied_mask = occ2d > 0 if np.any(occupied_mask): print(f"  高度统计：min={z_hi[occupied_mask].min():.2f}m, max={z_hi[occupied_mask].max():.2f}m, mean={z_hi[occupied_mask].mean():.2f}m") if __name__ == "__main__": main()